  var ea = array<i32, 12>(0, 2, 4, 6, 0, 1, 4, 5, 0, 1, 2, 3);
  var eb = array<i32, 12>(1, 3, 5, 7, 2, 3, 6, 7, 4, 5, 6, 7);
  var sx : f32 = 0.0;
  var sy : f32 = 0.0;
  var sz : f32 = 0.0;
  var n : f32 = 0.0;
