  outPositions[vo * 3 + 1] = p.y;
  outPositions[vo * 3 + 2] = p.z;
  outNormals[vo * 3 + 0] = nrm.x;
  outNormals[vo * 3 + 1] = nrm.y;
  outNormals[vo * 3 + 2] = nrm.z;
